// The SERVER-SIDE OVER-ORDER GUARD (mirrors planning.check_order_capacity).
// Inbound is RESERVED capacity so you don't over-order into space about to fill.
const d = $json;
const free_to_order = Math.max(0, d.warehouse_capacity - d.on_hand - d.inbound_reserved);
const committed = d.on_hand + d.inbound_reserved;
const committed_pct = d.warehouse_capacity > 0 ? Math.round(100 * committed / d.warehouse_capacity) : 0;
const req = Math.max(0, d.requested_units);

let verdict, allowed, message;
if (req <= free_to_order)      { verdict = 'ok';     allowed = req;            message = `OK — ${req} fits (${free_to_order} free).`; }
else if (free_to_order > 0)    { verdict = 'clamp';  allowed = free_to_order;   message = `CLAMPED — only ${free_to_order} of ${req} fit; reduce or free space.`; }
else                           { verdict = 'reject'; allowed = 0;               message = `REJECTED — warehouse full (0 free).`; }

return [{ json: {
  warehouse_capacity: d.warehouse_capacity,
  on_hand: d.on_hand, inbound_reserved: d.inbound_reserved,
  committed, committed_pct,
  free_to_order, requested: req,
  verdict, allowed, message
}}];
